@* Static SSR component — rendered in the layout on every navigation. *@
@* It reads directly from HttpContext + the singleton store. *@
@using sv_a33fe6fdec6e40d7833575325638ec29.Services
@using sv_a33fe6fdec6e40d7833575325638ec29.Models

@inject IHttpContextAccessor HttpContextAccessor
@inject WizardStateStore Store

@{
    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    var isWizard = path.StartsWith("/apply", StringComparison.OrdinalIgnoreCase);
}

@if (isWizard)
{
    var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
    var state = Store.GetOrCreate(sessionId);

    <nav class="wizard-progress d-flex align-items-center gap-2 px-4 py-2 bg-light border-bottom">
        <strong class="me-2">Application: Step @(GetCurrentStep(path)) of @TotalSteps</strong>
        @for (int i = 1; i <= TotalSteps; i++)
        {
            var step = i;
            var isCurrent = step == GetCurrentStep(path);
            var isCompleted = state.CompletedSteps.Contains(step);
            var cssClass = isCurrent ? "badge bg-primary" : isCompleted ? "badge bg-success" : "badge bg-secondary";

            <span class="@cssClass">@StepLabels[step - 1]</span>
        }
    </nav>
}

@code {
    private const int TotalSteps = 4;

    private static readonly string[] StepLabels =
        ["Personal Info", "Experience", "References", "Review"];

    private static int GetCurrentStep(string path) => path.ToLowerInvariant() switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 1
    };
}

@page "/apply/personal-info"
@rendermode InteractiveServer

@using sv_a33fe6fdec6e40d7833575325638ec29.Services
@using sv_a33fe6fdec6e40d7833575325638ec29.Models

@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav

@implements IDisposable

<PageTitle>Step 1 — Personal Info</PageTitle>
<h1>Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="state.Name" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="state.Email" @bind:event="oninput" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next: Experience →</button>
</div>

@code {
    private WizardState state = new();
    private string sessionId = "";
    private PersistentComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        // During prerender: HttpContext is available — capture session ID.
        // During interactive: HttpContext is null — retrieve persisted session ID.
        _sub = PersistentState.RegisterOnPersisting(PersistSessionId);

        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            sessionId = httpContext.Session.Id;
        }
        else
        {
            PersistentState.TryTakeFromJson<string>("sessionId", out var restored);
            sessionId = restored ?? "";
        }

        state = Store.GetOrCreate(sessionId);
        state.CurrentStep = 1;
        state.LastAccessed = DateTime.UtcNow;
    }

    private Task PersistSessionId()
    {
        PersistentState.PersistAsJson("sessionId", sessionId);
        return Task.CompletedTask;
    }

    private void Next()
    {
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    public void Dispose() => _sub.Dispose();
}

