@using sv_a33fe6fdec6e40d7833575325638ec29.Services
@using sv_a33fe6fdec6e40d7833575325638ec29.Models

@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav

@implements IDisposable

<PageTitle>Step 4 — Review</PageTitle>
<h1>Review Your Application</h1>

<div class="card mb-3 p-3">
    <h4>Personal Info</h4>
    <p><strong>Name:</strong> @state.Name</p>
    <p><strong>Email:</strong> @state.Email</p>
</div>

<div class="card mb-3 p-3">
    <h4>Experience</h4>
    @if (state.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    @foreach (var job in state.Jobs)
    {
        <p>@job.Title at @job.Company (@job.Years years)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h4>References</h4>
    @if (state.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    @foreach (var r in state.References)
    {
        <p>@r.Name — @r.Relationship — @r.Phone</p>
    }
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>
        ← Back
    </button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private WizardState state = new();
    private string sessionId = "";
    private bool submitted;
    private PersistentComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(PersistSessionId);

        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            sessionId = httpContext.Session.Id;
        }
        else
        {
            PersistentState.TryTakeFromJson<string>("sessionId", out var restored);
            sessionId = restored ?? "";
        }

        state = Store.GetOrCreate(sessionId);
        state.CurrentStep = 4;
        state.LastAccessed = DateTime.UtcNow;
    }

    private Task PersistSessionId()
    {
        PersistentState.PersistAsJson("sessionId", sessionId);
        return Task.CompletedTask;
    }

    private void Submit()
    {
        state.CompletedSteps.Add(4);
        submitted = true;
        // In production: save to database, then call Store.Remove(sessionId)
    }

    public void Dispose() => _sub.Dispose();
}

