1. @* Static SSR component — rendered in the layout on every navigation. *@
2. @* It reads directly from HttpContext + the singleton store. *@
3. @using sv_a33fe6fdec6e40d7833575325638ec29.Services
4. @using sv_a33fe6fdec6e40d7833575325638ec29.Models
5. 
6. @inject IHttpContextAccessor HttpContextAccessor
7. @inject WizardStateStore Store
8. 
9. @{
10.     var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
11.     var isWizard = path.StartsWith("/apply", StringComparison.OrdinalIgnoreCase);
12. }
13. 
14. @if (isWizard)
15. {
16.     var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
17.     var state = Store.GetOrCreate(sessionId);
18. 
19.     <nav class="wizard-progress d-flex align-items-center gap-2 px-4 py-2 bg-light border-bottom">
20.         <strong class="me-2">Application: Step @(GetCurrentStep(path)) of @TotalSteps</strong>
21.         @for (int i = 1; i <= TotalSteps; i++)
22.         {
23.             var step = i;
24.             var isCurrent = step == GetCurrentStep(path);
25.             var isCompleted = state.CompletedSteps.Contains(step);
26.             var cssClass = isCurrent ? "badge bg-primary" : isCompleted ? "badge bg-success" : "badge bg-secondary";
27. 
28.             <span class="@cssClass">@StepLabels[step - 1]</span>
29.         }
30.     </nav>
31. }
32. 
33. @code {
34.     private const int TotalSteps = 4;
35. 
36.     private static readonly string[] StepLabels =
37.         ["Personal Info", "Experience", "References", "Review"];
38. 
39.     private static int GetCurrentStep(string path) => path.ToLowerInvariant() switch
40.     {
41.         "/apply/personal-info" => 1,
42.         "/apply/experience" => 2,
43.         "/apply/references" => 3,
44.         "/apply/review" => 4,
45.         _ => 1
46.     };
47. }
48.

